import{allNodes}from"./instance.js";const outputFormats={},toOutputFormat=(o,r)=>{if(r in outputFormats)return outputFormats[r](o);throw Error(`The '${r}' error format is not supported`)};outputFormats.FLAG=o=>({valid:o.valid}),outputFormats.BASIC=o=>{const r={valid:o.valid};if(!o.valid){r.errors=[];for(const e of allNodes(o))for(var[t,a]of Object.entries(e.errors).reverse())e.valid||r.errors.unshift({keyword:a,absoluteKeywordLocation:t,instanceLocation:e.uri(),valid:e.valid});r.errors.pop()}return r};export{toOutputFormat};